export type PracticalExample = {
  scenario: string;
  actions: string[];
  outcome: string;
};

export type PracticalExampleLens = {
  constraints: string[];
  artifacts: string[];
  failureSignals: string[];
  reviewQuestions: string[];
};

const example = (scenario: string, actions: string[], outcome: string): PracticalExample => ({
  scenario,
  actions,
  outcome,
});

const lens = (
  constraints: string[],
  artifacts: string[],
  failureSignals: string[],
  reviewQuestions: string[],
): PracticalExampleLens => ({
  constraints,
  artifacts,
  failureSignals,
  reviewQuestions,
});

